from haystack.components.generators import OpenAIGenerator

from vex import VexFaithfulnessVerifier

@component
class CitingSynthesizer:
    @component.output_types(response=str, citations=list)
    def run(self, contexts: list, query: str) -> dict:
        generator = OpenAIGenerator(model="gpt-4o")

        prompt = f"""Answer using ONLY these sources:
        {format_sources(contexts)}
        Query: {query}
        Use [citation_id] format."""

        result = generator.run(prompt)

        # Vex faithfulness check
        verifier = VexFaithfulnessVerifier()
        faith_score = verifier.verify(
            response=result["generation"],
            contexts=contexts,
            query=query
        )

        if faith_score < 0.95:
            raise ValueError(f"Low faithfulness: {faith_score}")

        return {
            "response": result["generation"],
            "citations": extract_citations(result["generation"])
        }

synth_pipe.add_component("synthesizer", CitingSynthesizer())

from typing import List
from haystack.dataclasses import Document

from vex import VexConsistencyChecker

@component
class MultiSourceVerifier:
    @component.output_types(consistent=bool, conflicts=list)
    def run(self, documents: List[Document]) -> dict:
        checker = VexConsistencyChecker()

        # Group by source type
        sources = {
            'vector': [d for d in documents if d.meta.get('source') == 'vector'],
            'sql': [d for d in documents if d.meta.get('source') == 'sql'],
            'web': [d for d in documents if d.meta.get('source') == 'web']
        }

        result = checker.verify_cross_source(
            sources=sources,
            checks=["factual_consistency", "temporal_consistency"]
        )

        return {
            "consistent": result.all_pass,
            "conflicts": result.conflicts
        }

consistency_pipe.add_component("multi_verifier", MultiSourceVerifier())
consistency_pipe.connect("retrievers", "multi_verifier.documents")

