from haystack import component
from typing import Any, Dict
from vex import VexClient

@component
class VexPipelineVerifier:
    """
    Vex verification component for Haystack pipelines
    """
    def __init__(self, api_key: str, verifications: list):
        self.client = VexClient(api_key=api_key)
        self.verifications = verifications

    @component.input_types(query=str, contexts=list, response=str)
    @component.output_types(valid=bool, score=float, issues=list)
    def run(
        self, 
        query: str, 
        contexts: list, 
        response: str = None
    ) -> Dict[str, Any]:

        results = self.client.batch_verify({
            "query_planning": query,
            "source_faithfulness": {"response": response, "contexts": contexts},
            "relevance": {"query": query, "contexts": contexts}
        })

        return {
            "valid": results.all_pass,
            "score": results.aggregate_score,
            "issues": results.issues
        }

